#!/usr/bin/env node
// Convert the SVG covers generated by scripts/generate-missing-covers.mjs
// into PNGs (Astro 5's image() schema returns string for some SVG paths,
// which then trips getImage's validator). Identified by mtime — only SVG
// covers in src/assets/blog/ and src/assets/courses/ that were written
// in the last 2 hours are touched; pre-existing hand-tuned SVG covers
// are left alone.

import {
  readFileSync,
  writeFileSync,
  readdirSync,
  existsSync,
  statSync,
  unlinkSync,
} from 'node:fs';
import { join, basename, dirname } from 'node:path';
import sharp from 'sharp';

const TWO_HOURS_MS = 2 * 60 * 60 * 1000;
const cutoff = Date.now() - TWO_HOURS_MS;

const ASSET_DIRS = ['src/assets/blog', 'src/assets/courses'];
const CONTENT_DIRS = ['src/content/blog', 'src/content/notebooks', 'src/content/courses'];

// Find SVGs written by the cover generator (recent mtime, -cover.svg suffix)
const targetSvgs = new Set();
for (const dir of ASSET_DIRS) {
  if (!existsSync(dir)) continue;
  for (const name of readdirSync(dir)) {
    if (!name.endsWith('-cover.svg')) continue;
    const path = join(dir, name);
    const stat = statSync(path);
    if (stat.mtimeMs >= cutoff) {
      targetSvgs.add(path.replace(/\\/g, '/'));
    }
  }
}

console.log(`found ${targetSvgs.size} recently-generated SVG covers to rasterize`);

// Rasterize SVG → PNG
async function rasterize(svgPath) {
  const buf = readFileSync(svgPath);
  const pngPath = svgPath.replace(/\.svg$/, '.png');
  await sharp(buf, { density: 150 })
    .resize(1200, 630, { fit: 'fill' })
    .png({ compressionLevel: 9 })
    .toFile(pngPath);
  return pngPath;
}

const svgToPng = new Map();
for (const svgPath of targetSvgs) {
  try {
    const pngPath = await rasterize(svgPath);
    svgToPng.set(svgPath, pngPath);
  } catch (err) {
    console.warn(`rasterize failed: ${svgPath} — ${err.message}`);
  }
}
console.log(`rasterized ${svgToPng.size} PNGs`);

// Update markdown frontmatter to point at PNG, then delete SVG
let mdUpdated = 0;
for (const dir of CONTENT_DIRS) {
  if (!existsSync(dir)) continue;
  for (const name of readdirSync(dir)) {
    if (!name.endsWith('.md') && !name.endsWith('.mdx')) continue;
    const path = join(dir, name);
    const raw = readFileSync(path, 'utf8');
    const m = raw.match(/^(---\r?\n)([\s\S]*?)(\r?\n---\r?\n?)([\s\S]*)$/);
    if (!m) continue;
    let fmText = m[2];
    let touched = false;

    // Find cover: lines pointing at a -cover.svg path that we just rasterized.
    // We don't fully parse YAML — just regex the cover line and check if the
    // referenced file is in our svgToPng set.
    const coverRe = /^(cover:\s*['"]?)(\.\.\/\.\.\/assets\/(?:blog|courses)\/[^'"\s]+-cover\.svg)(['"]?)\s*$/m;
    const match = fmText.match(coverRe);
    if (match) {
      const relPath = match[2];
      // Resolve the relative path from the markdown file's directory
      const absSvgPath = join(dirname(path), relPath).replace(/\\/g, '/');
      // Normalize Windows paths to forward slashes for comparison
      const normalizedSvgPath = absSvgPath.split('/').map((s) => s).join('/');
      // Try direct match first
      let isOurs = svgToPng.has(normalizedSvgPath);
      // Try without absolute prefix (might be relative-ish)
      if (!isOurs) {
        for (const key of svgToPng.keys()) {
          if (key.endsWith(basename(relPath))) { isOurs = true; break; }
        }
      }
      if (isOurs) {
        const newRelPath = relPath.replace(/\.svg$/, '.png');
        fmText = fmText.replace(coverRe, `$1${newRelPath}$3`);
        touched = true;
      }
    }

    if (touched) {
      writeFileSync(path, m[1] + fmText + m[3] + m[4], 'utf8');
      mdUpdated++;
    }
  }
}
console.log(`updated ${mdUpdated} markdown frontmatter references`);

// Delete the old SVGs
let svgDeleted = 0;
for (const svgPath of svgToPng.keys()) {
  try {
    unlinkSync(svgPath);
    svgDeleted++;
  } catch (err) {
    console.warn(`delete failed: ${svgPath} — ${err.message}`);
  }
}
console.log(`deleted ${svgDeleted} old SVG covers`);
console.log('done.');
